WITH pixel AS ( SELECT 'Google Pixel' AS group_name, SUM(s.shipped_units) AS shipped_units, SUM(c.conceded_units) AS conceded_units FROM shipped_raw s LEFT JOIN concession_raw c ON c.asin = s.asin AND c.mapped_year = s.year AND c.mapped_month = s.month AND c.mapped_week = s.week WHERE s.item_name ILIKE '%pixel%'), iphone AS ( SELECT 'iPhone' AS group_name, SUM(s.shipped_units) AS shipped_units, SUM(c.conceded_units) AS conceded_units FROM shipped_raw s LEFT JOIN concession_raw c ON c.asin = s.asin AND c.mapped_year = s.year AND c.mapped_month = s.month AND c.mapped_week = s.week WHERE s.item_name ILIKE '%iphone%') SELECT group_name, shipped_units, conceded_units, (conceded_units * 100.0) / NULLIF(shipped_units, 0) AS return_rate_pct FROM (SELECT * FROM pixel UNION ALL SELECT * FROM iphone) t;